async (params, browser) => {
  // Open course reviews
  await browser.open(`${params.course_url}#reviews`)

  // Wait for page to load
  await browser.waitForSelector('h1, [data-purpose=\'lead-title\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to reviews section
  await browser.scroll({ direction: 'down', amount: 5000 })

  await browser.wait(2000)

  // Scroll to load more reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[class*="review--review"], [data-purpose="review-comment-content"], [class*="ReviewCard"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('[class*="review--reviewer"], [class*="author"], [class*="user-name"]'); const ratingEl = el.querySelector('[class*="star-rating"], [class*="rating"] span, [aria-label*="Rating"]'); const contentEl = el.querySelector('[class*="review--content"], [data-purpose="review-comment-content"], [class*="body"]'); const dateEl = el.querySelector('[class*="review--date"], time, [class*="date"]'); const helpfulEl = el.querySelector('[class*="helpful"], [class*="votes"]'); if (contentEl && contentEl.textContent.trim().length > 0) { reviews.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', content: contentEl.textContent.trim().substring(0, 500), date: dateEl ? dateEl.textContent.trim() : '', helpful: helpfulEl ? helpfulEl.textContent.trim() : '' }); } } const overallEl = document.querySelector('[data-purpose="rating-number"], [class*="average-rating"]'); const totalEl = document.querySelector('[class*="review-count"], [class*="total-reviews"]'); return { overall_rating: overallEl ? overallEl.textContent.trim() : '', total_reviews: totalEl ? totalEl.textContent.trim() : '', scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
